import os
from PIL import Image
import numpy as np
from scipy.stats import wasserstein_distance
from tqdm import tqdm
from concurrent.futures import ProcessPoolExecutor
import concurrent

# 计算两个图像之间的距离
def calculate_image_distance(img1, img2):
    # 将图像转换为直方图数据
    hist1 = np.array(img1.histogram()).astype('float32')
    hist2 = np.array(img2.histogram()).astype('float32')
    
    # 计算差异，这里使用的是欧几里得距离
    distance = np.sqrt(np.sum((hist1 - hist2) ** 2))
    return distance


# 计算两个图像之间的Wasserstein距离
def calculate_wasserstein_distance(img1, img2):
    # 将图像转换为直方图数据
    hist1 = np.array(img1.histogram()).astype('float32')
    hist2 = np.array(img2.histogram()).astype('float32')
    
    # 为了计算Wasserstein距离，我们需要直方图的每个通道
    hist1_channels = [hist1[i:i + 256] for i in range(0, 768, 256)]
    hist2_channels = [hist2[i:i + 256] for i in range(0, 768, 256)]
    
    # 计算每个通道的Wasserstein距离并求和
    distance = sum(wasserstein_distance(hist1_channels[i], hist2_channels[i]) for i in range(3))
    return distance

# 多线程处理每个模型图像的最小距离查找
def process_model_image(model_image_name, gt_images, gt_dir, model_dir, distance_function):
    model_image_path = os.path.join(model_dir, model_image_name)
    model_image = Image.open(model_image_path)
    
    min_distance = float('inf')
    closest_gt_image_name = None
    
    for gt_image_name in gt_images:
        gt_image_path = os.path.join(gt_dir, gt_image_name)
        gt_image = Image.open(gt_image_path)
        
        distance = distance_function(model_image, gt_image)
        
        if distance < min_distance:
            min_distance = distance
            closest_gt_image_name = gt_image_name
            
    return model_image_name, closest_gt_image_name, min_distance


# 使用多进程来查找最小距离
def find_minimum_distances_multiprocessed(gt_dir, model_dir, distance_function, num_processes):
    model_images = [f for f in os.listdir(model_dir) if f.endswith('.png')]
    gt_images = [f for f in os.listdir(gt_dir) if f.endswith('.png')]
    
    min_distances = {}
    
    with ProcessPoolExecutor(max_workers=num_processes) as executor:
        # 使用map来并行处理所有模型图像
        futures = [executor.submit(process_model_image, model_image_name, gt_images, gt_dir, model_dir, distance_function) for model_image_name in model_images]
        for future in tqdm(concurrent.futures.as_completed(futures), total=len(model_images)):
            model_image_name, closest_gt_image_name, min_distance = future.result()
            min_distances[model_image_name + '&' + closest_gt_image_name] = min_distance
    
    return min_distances

# 定义子目录路径
gt_dir = 'test_gt'
model_dir = 'test_model1000000'
num_processes = os.cpu_count() # 使用所有可用的CPU核心

# 计算最小欧几里得距离
min_distances_dict = find_minimum_distances_multiprocessed(gt_dir, model_dir, calculate_image_distance, num_processes)
print(min_distances_dict)

# 计算最小Wasserstein距离
min_distances_wdict = find_minimum_distances_multiprocessed(gt_dir, model_dir, calculate_wasserstein_distance, num_processes)
print(min_distances_wdict)

os.mkdir('./l2')
os.mkdir('./emd')

# 遍历字典，把字典里的每个键对应的一对图像左右拼接成一张图，欧几里得距离字典里的输出到l2文件夹，Wasserstein距离字典里的输出到emd文件夹

def stitch_and_save_images(distances_dict, gt_dir, model_dir, output_dir):
    # 拼接图像并保存到指定文件夹
    if not os.path.exists(output_dir):
        os.makedirs(output_dir)
    
    for key, _ in tqdm(distances_dict.items()):
        model_image_name, gt_image_name = key.split('&')
        
        model_image_path = os.path.join(model_dir, model_image_name)
        gt_image_path = os.path.join(gt_dir, gt_image_name)
        
        model_image = Image.open(model_image_path)
        gt_image = Image.open(gt_image_path)
        
        # 拼接图像
        dst = Image.new('RGB', (model_image.width + gt_image.width, model_image.height))
        dst.paste(model_image, (0, 0))
        dst.paste(gt_image, (model_image.width, 0))
        
        # 保存拼接后的图像
        dst.save(os.path.join(output_dir, model_image_name))

# 使用find_minimum_distances_multithreaded函数的输出来创建拼接图像
stitch_and_save_images(min_distances_dict, gt_dir, model_dir, './l2')
stitch_and_save_images(min_distances_wdict, gt_dir, model_dir, './emd')

